import React, { useCallback, useEffect, useMemo, useState } from 'react';
import axios from 'axios';

const statusBadge = (status) => {
    const base = 'inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold tracking-wide';
    switch (status) {
        case 'AVAILABLE':
            return `${base} bg-emerald-100 text-emerald-700 border border-emerald-200`;
        case 'IN USE':
            return `${base} bg-amber-100 text-amber-700 border border-amber-200`;
        default:
            return `${base} bg-slate-100 text-slate-700 border border-slate-200`;
    }
};

const StatCard = ({ title, value, accent }) => (
    <div className="relative overflow-hidden rounded-2xl bg-white border border-gray-100 shadow-sm p-4">
        <div className={`absolute inset-x-0 top-0 h-1 ${accent}`} />
        <p className="text-sm text-gray-500">{title}</p>
        <p className="text-3xl font-extrabold text-gray-900 mt-1">{value}</p>
    </div>
);

const navItems = [
    { id: 'inventory', label: 'Inventory', icon: '📦', blurb: 'All stock and components' },
    { id: 'builds', label: 'Build Planner', icon: '🛠️', blurb: 'Draft and track PC builds' },
    { id: 'shortages', label: 'Shortages', icon: '🚨', blurb: 'See what parts block builds' },
    { id: 'picker', label: 'PC Part Picker', icon: '🧮', blurb: 'Cost out potential builds' },
    { id: 'finance', label: 'Financial Planner', icon: '💹', blurb: 'Business budgets & projections' },
    { id: 'about', label: 'About', icon: 'ℹ️', blurb: 'WhatAPC vision & strategy' },
    { id: 'links', label: 'Social & Links', icon: '🔗', blurb: 'Quick links to socials, stores, pages' },
    { id: 'suppliers', label: 'Suppliers', icon: '🤝', blurb: 'Vendors, pricing, contacts' },
    { id: 'orders', label: 'Orders', icon: '🧾', blurb: 'Quotes, invoices, sales' },
    { id: 'tasks', label: 'Tasks', icon: '✅', blurb: 'Follow-ups and reminders' },
];

const InventoryList = () => {
    const [inventory, setInventory] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState('');
    const [itemTypeFilter, setItemTypeFilter] = useState('');
    const [brandFilter, setBrandFilter] = useState('');
    const [lowOnly, setLowOnly] = useState(false);
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const [sortField, setSortField] = useState('inventory_id');
    const [sortOrder, setSortOrder] = useState('asc');
    const [selectedItems, setSelectedItems] = useState([]);
    const [compactTable, setCompactTable] = useState(false);
    const [bulkAction, setBulkAction] = useState('');
    const [stats, setStats] = useState({ total: 0, available: 0, inUse: 0, lowStock: 0 });
    const [formData, setFormData] = useState({
        inventory_id: '',
        item_type: '',
        brand: '',
        model: '',
        component: '',
        qty: 1,
        details: '',
        socket_or_interface: '',
        status: 'AVAILABLE',
        used_in: '',
        ownership: 'INVENTORY',
        test_status: 'UNTESTED',
        cooler_required: '',
        notes: '',
        photo_refs: '',
        price_paid: '',
        source: '',
        seller: '',
        location_bin: '',
        location_shelf: '',
        location_notes: ''
    });
    const [showForm, setShowForm] = useState(false);
    const [editingItem, setEditingItem] = useState(null);
    const [importFile, setImportFile] = useState(null);
    const [thresholds, setThresholds] = useState({
        'cpu cooler': 2,
        cooler: 2,
        fan: 4,
        'case fan': 4,
        'thermal paste': 3,
    });
    const [thresholdModal, setThresholdModal] = useState(false);
    const [newThreshold, setNewThreshold] = useState({ type: '', value: 2 });
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [activePage, setActivePage] = useState('inventory');
    const [fullInventory, setFullInventory] = useState([]);
    const [builds, setBuilds] = useState(() => {
        try {
            return JSON.parse(localStorage.getItem('buildPlans')) || [];
        } catch (_) {
            return [];
        }
    });
